function uuidv4() {
  if (globalThis.crypto && typeof crypto.randomUUID === 'function') return crypto.randomUUID();
  return 'xxxxxxxx-xxxx-4xxx-yxxx-xxxxxxxxxxxx'.replace(/[xy]/g, function (c) {
    const r = Math.random() * 16 | 0;
    const v = c === 'x' ? r : (r & 0x3 | 0x8);
    return v.toString(16);
  });
}

const root = $input.first().json || {};
let body = root.body || root;
// Replay payloads may carry the full webhook envelope ({headers,query,body}); unwrap it.
if (body && typeof body === 'object' && body.body && typeof body.body === 'object' && (body.headers || body.query || body.webhookUrl)) body = body.body;
const replay = !!root.replay;
const response_required = !!root.body && !replay;

// Shared-secret gate for the public webhook path; cron and replay entries are trusted.
// Unset secret = open gate (dev degrade, same spirit as the TELEGRAM_* fallbacks).
const secret = $env.FLOWOPS_WEBHOOK_SECRET || '';
const reqHeaders = (root.headers && typeof root.headers === 'object') ? root.headers : {};
const authorized = !response_required || !secret || String(reqHeaders['x-flowops-secret'] || '') === secret;

const now = new Date();
const hourBucket = now.toISOString().slice(0, 13);
// Cron dedupes per hour (fires every 6h; hour bucket blocks double-fires without
// starving the next scheduled run). A MANUAL webhook trigger dedupes per MINUTE so
// an operator deliberately re-running is not answered 202-then-silently-skipped
// within the same hour. Caller may override with body.event_id / body.run_id.
const event_id = body.event_id || body.run_id || ('health-scan-' + (response_required ? 'manual-' + now.toISOString().slice(0, 16) : hourBucket));
// Clamp the threshold: out of range would flag every tenant, and a non-numeric value
// becomes NaN whose comparisons are all false (watch band silently disabled).
const clampT = (v) => { const x = Number(v); return Number.isFinite(x) && x >= 0 && x <= 100 ? x : null; };
const threshold = clampT(body.threshold) ?? clampT($env.HEALTH_RISK_THRESHOLD) ?? 70;
const correlation_id = replay && root.correlation_id ? root.correlation_id : uuidv4();

return [{ json: {
  event_id,
  idem_key: 'health:' + event_id,
  threshold,
  replay,
  response_required,
  authorized,
  correlation_id,
  execution_id: String($execution.id),
  supabase_url: ($env.SUPABASE_URL || '').replace(/\/$/, '')
} }];

const p = $('Normalize Run').first().json;
const H = { apikey: $env.SUPABASE_SERVICE_KEY, Authorization: 'Bearer ' + $env.SUPABASE_SERVICE_KEY, accept: 'application/json' };
const helpers = this.helpers;
// PostgREST caps unpaged responses (max-rows, commonly 1000): page with Range headers
// so tenants past the cap are not silently dropped from the scan. Explicit order=
// keeps pages stable across requests.
async function getAll(path) {
  const page = 1000;
  let out = [];
  for (let from = 0; ; from += page) {
    const rows = await helpers.httpRequest({ method: 'GET', url: p.supabase_url + path, headers: Object.assign({ Range: from + '-' + (from + page - 1), 'Range-Unit': 'items' }, H), json: true, timeout: 30000 });
    if (!Array.isArray(rows) || rows.length === 0) break;
    out = out.concat(rows);
    if (rows.length < page) break;
  }
  return out;
}
const tenants = await getAll('/rest/v1/tenants?status=eq.active&select=id,name,plan,region,status,health_score&order=id');
const signals = await getAll('/rest/v1/v_health_latest?select=tenant_id,tenant_name,metric,latest_value,prev_value,delta,latest_ts&order=tenant_id,metric');
const byTenant = new Map();
for (const t of tenants || []) byTenant.set(t.id, { tenant: t, signals: [] });
for (const s of signals || []) {
  if (!byTenant.has(s.tenant_id)) continue;
  byTenant.get(s.tenant_id).signals.push(s);
}
function n(v, fallback = 0) {
  const x = Number(v);
  return Number.isFinite(x) ? x : fallback;
}
function classify(tenant, sigs) {
  const reasons = [];
  let score = n(tenant.health_score, 100);
  for (const s of sigs) {
    const latest = n(s.latest_value, 0);
    const delta = n(s.delta, 0);
    if (s.metric === 'login_frequency' && (latest <= 5 || delta <= -8)) reasons.push('login drop');
    if (s.metric === 'feature_usage' && (latest <= 15 || delta <= -20)) reasons.push('feature usage drop');
    if (s.metric === 'ticket_volume' && (latest >= 10 || delta >= 5)) reasons.push('ticket volume spike');
  }
  // Severity bands: critical = very low score OR multiple deteriorating signals;
  // high = low score (clinical); watch = a single signal on an otherwise-healthy
  // tenant OR score below the configurable threshold. A single weak signal no longer
  // forces 'high' at score 100 (would page CSMs on a healthy tenant).
  let level = 'low';
  if (score < 40 || reasons.length >= 2) level = 'critical';
  else if (score < 55) level = 'high';
  else if (reasons.length >= 1 || score < p.threshold) level = 'watch';
  return { level, reasons };
}
const risks = [];
for (const item of byTenant.values()) {
  const c = classify(item.tenant, item.signals);
  if (c.level === 'low') continue;
  risks.push({
    tenant_id: item.tenant.id,
    tenant_name: item.tenant.name,
    plan: item.tenant.plan,
    region: item.tenant.region,
    health_score: item.tenant.health_score,
    risk_level: c.level,
    reasons: c.reasons,
    playbook: c.level === 'critical' ? 'exec-save-plan' : (c.level === 'high' ? 'csm-risk-review' : 'watchlist'),
    signals: item.signals.map(s => ({ metric: s.metric, latest_value: s.latest_value, prev_value: s.prev_value, delta: s.delta }))
  });
}
const riskRank = { critical: 0, high: 1, watch: 2 };
risks.sort((a, b) => (riskRank[a.risk_level] ?? 9) - (riskRank[b.risk_level] ?? 9));
return [{ json: { tenant_id: null, correlation_id: p.correlation_id, risk_count: risks.length, risks, generated_at: new Date().toISOString() } }];

const s = $('Scan Health Risks').first().json;
const top = (s.risks || []).slice(0, 5);
const text = ['FlowOps health scan', 'Risks: ' + s.risk_count, 'Correlation: ' + s.correlation_id, ''].concat(top.map(r => r.risk_level.toUpperCase() + ': ' + r.tenant_name + ' - ' + r.reasons.join(', ') + ' -> ' + r.playbook)).join('\n');
let alert_delivered = false;
let notice = null;
const token = $env.TELEGRAM_BOT_TOKEN;
const chat = $env.TELEGRAM_CHAT_ID;
if (token && chat && s.risk_count > 0) {
  try {
    // Plain text on purpose: parse_mode:'Markdown' makes Telegram 400 on unbalanced
    // '_' / '*' in tenant names, silently killing the alert this service exists to send.
    await this.helpers.httpRequest({ method: 'POST', url: 'https://api.telegram.org/bot' + token + '/sendMessage', body: { chat_id: chat, text }, json: true, timeout: 15000 });
    alert_delivered = true;
  } catch (e) {
    // Never persist the raw error: n8n error messages can embed the request URL,
    // which contains the bot token. audit_log is anon-readable in dev.
    notice = 'telegram failed: ' + String(e && e.message ? e.message : e).split(token).join('[token]');
  }
} else if (s.risk_count === 0) {
  notice = 'telegram skipped: no risks';
} else {
  notice = 'telegram skipped: TELEGRAM_BOT_TOKEN / TELEGRAM_CHAT_ID not set';
}
return [{ json: { alert_delivered, notice, risk_count: s.risk_count, risks: s.risks, correlation_id: s.correlation_id } }];

const n = $('Notify Telegram').first().json;
// Compact summary, not the full risks[]: per-tenant signal deltas are queryable live
// via v_health_latest, and dumping them into audit every run bloats audit_log. Keep
// enough to reconstruct what this scan decided (count + per-level breakdown + tenant
// id / level / reasons).
const src = Array.isArray(n.risks) ? n.risks : [];
const byLevel = { critical: 0, high: 0, watch: 0 };
const tenant_levels = [];
for (const r of src) {
  byLevel[r.risk_level] = (byLevel[r.risk_level] || 0) + 1;
  tenant_levels.push({ tenant_id: r.tenant_id, risk_level: r.risk_level, reasons: r.reasons });
}
return [{ json: { tenant_id: null, correlation_id: n.correlation_id, service: 'health', step: 'route-playbook', status: 'success', payload: { risk_count: n.risk_count, by_level: byLevel, tenant_levels, telegram_delivered: n.alert_delivered, notice: n.notice } } }];
